/* ============================================================
 * Founders OS — setup-page generators (canonical, shared)
 * ============================================================
 * Pure, dependency-free, DOM-free generation functions for the setup
 * wizard: input object in, file string out. No `window`, no `fetch`, no
 * imports. This is the SINGLE SOURCE for the standalone setup page
 * (integrations/setup-page/index.html, which inlines this file at build
 * via build.js) AND the marketing-site setup page (synced from here by
 * tools/sync-setup-generators - never hand-edit the copy). Keeping the
 * generators in one place is what kills the drift between the two pages.
 *
 * Each page keeps its own DOM wiring and calls these for content. Loaded
 * as a classic script it attaches `FoundersOSSetup` to the global; under
 * Node (tests) it is available via module.exports. No ESM so the inlined
 * standalone page works opened straight from disk.
 *
 * Scheduler note: the generated OS units point at the tick WRAPPER
 * (integrations/scheduler/foundersos-tick.{sh,cmd}), not the bare CLI, so
 * one scheduled job runs `detect` then `run --hold-only` serially. The
 * wrapper reads credentials from the env file this module also generates
 * (default ~/.config/founders-os/foundersos-tick.env), so the units carry no secrets.
 * ============================================================ */
(function (root) {
  "use strict";

  // ── Defaults (overridable via the opts object) ───────────
  var DEFAULTS = {
    label: "com.foundersos.tick",
    // ABSOLUTE on purpose: launchd and systemd do NOT expand "~", so a
    // tilde path silently fails to launch (launchd exits 78/EX_CONFIG).
    // The page collects the user's real absolute path; this placeholder is
    // a loud fallback, never a working-but-wrong default.
    wrapperPathUnix: "/ABSOLUTE/PATH/TO/foundersos-tick.sh",
    wrapperPathWin: "%USERPROFILE%\\foundersos-tick.cmd",
    envPath: "~/.config/founders-os/foundersos-tick.env",
    logPath: "/tmp/foundersos-tick.log",
    cadence: "hourly", // "hourly" | "daily"
    dailyHour: 6, // used when cadence === "daily"
    taskName: "FoundersOS Tick",
  };

  function withDefaults(opts) {
    var o = {};
    for (var k in DEFAULTS) o[k] = DEFAULTS[k];
    if (opts) for (var j in opts) if (opts[j] != null && opts[j] !== "") o[j] = opts[j];
    return o;
  }

  // ── setup.sql: substitute the chosen embedding dimension ──
  // The raw setup.sql ships with vector(1024) as the sentinel; the page
  // replaces it with the provider's dimension. Pure string transform.
  function sqlForDimension(raw, dim) {
    return String(raw).replace(/vector\(1024\)/g, "vector(" + dim + ")");
  }

  // ── mcp.json ──────────────────────────────────────────────
  // env: the resolved environment object (built by the page from its DOM).
  // opts.useLatest pins @latest vs the bare package spec.
  function buildMcpJson(env, opts) {
    var useLatest = !!(opts && opts.useLatest);
    var pkg = "@ourthinktank/founders-os" + (useLatest ? "@latest" : "");
    return { mcpServers: { "founders-os": { command: "npx", args: ["-y", pkg], env: env || {} } } };
  }

  // ── env file (creds for the scheduled wrapper) ───────────
  // Scheduled jobs do not inherit your shell profile, so the wrapper loads
  // these from a file. Same env the MCP server uses, as KEY=value lines.
  // The env file is `source`d by the wrapper, so a value with whitespace
  // MUST be quoted - an unquoted `KEY=a b` is parsed as "run command b with
  // KEY=a", which silently fails (this bites FOUNDERSOS_TICK_BIN, an npx /
  // node command with spaces). Quote whitespace values; escape " and \.
  function envLine(k, v) {
    var s = String(v);
    if (/\s/.test(s)) s = '"' + s.replace(/(["\\])/g, "\\$1") + '"';
    return k + "=" + s;
  }

  function buildEnvFile(env) {
    var e = env || {};
    var lines = [
      "# Founders OS tick credentials — loaded by foundersos-tick.sh/.cmd.",
      "# Keep this file private (chmod 600). Generated by the setup page.",
    ];
    var order = [
      "FOUNDERSOS_TICK_BIN",
      "SUPABASE_URL", "SUPABASE_SECRET_KEY",
      "FOUNDERS_OS_COMPANY_ID", "FOUNDERS_OS_USER_ID", "FOUNDERS_OS_TIMEZONE",
      "EMBEDDING_PROVIDER", "EMBEDDING_MODEL", "EMBEDDING_DIM",
      "OPENAI_API_KEY",
      "AWS_ACCESS_KEY_ID", "AWS_SECRET_ACCESS_KEY", "AWS_DEFAULT_REGION",
      "OLLAMA_BASE_URL",
      // Optional: model-driven full run (founders-os-tick run --execute).
      "FOUNDERSOS_AGENT_PROVIDER", "FOUNDERSOS_AGENT_MODEL", "ANTHROPIC_API_KEY",
    ];
    var seen = {};
    for (var i = 0; i < order.length; i++) {
      var k = order[i];
      seen[k] = true;
      if (e[k] != null && e[k] !== "") lines.push(envLine(k, e[k]));
    }
    // Any extra keys the page added that we did not enumerate.
    for (var key in e) {
      if (!seen[key] && e[key] != null && e[key] !== "") lines.push(envLine(key, e[key]));
    }
    // Optional full-run section, always shown as commented guidance so a
    // self-hoster can enable the model-driven `run --execute` without hunting
    // for the variable names. Leave unset to keep the safe hold-only posture.
    // Honest framing: full run detects, withholds, records, and reconciles -
    // it never sends or executes an external action; everything outside
    // Founders OS is staged for your approval.
    lines.push(
      "",
      "# ── Optional: model-driven full run (founders-os-tick run --execute) ──",
      "# A model triages the inbox and drafts follow-ups. It still only detects,",
      "# withholds, records, and reconciles - external actions are staged for your",
      "# approval, never sent. Leave unset to keep the hold-only posture.",
      "#   FOUNDERSOS_AGENT_PROVIDER=anthropic        # or: openai",
      "#   FOUNDERSOS_AGENT_MODEL=claude-sonnet-4-6   # or e.g. gpt-4.1",
      "#   ANTHROPIC_API_KEY=sk-ant-...               # OpenAI reuses OPENAI_API_KEY above"
    );
    return lines.join("\n") + "\n";
  }

  // ── Cadence helpers ──────────────────────────────────────
  function cronExpr(o) {
    return o.cadence === "daily" ? "0 " + o.dailyHour + " * * *" : "0 * * * *";
  }
  function systemdOnCalendar(o) {
    return o.cadence === "daily"
      ? "*-*-* " + pad2(o.dailyHour) + ":00:00"
      : "hourly";
  }
  function pad2(n) { return (n < 10 ? "0" : "") + n; }

  // ── launchd (macOS) — points at the wrapper ──────────────
  function buildLaunchdPlist(opts) {
    var o = withDefaults(opts);
    var interval = o.cadence === "daily"
      ? "<dict><key>Hour</key><integer>" + o.dailyHour + "</integer><key>Minute</key><integer>0</integer></dict>"
      : "<dict><key>Minute</key><integer>0</integer></dict>";
    return [
      '<?xml version="1.0" encoding="UTF-8"?>',
      '<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">',
      '<plist version="1.0">',
      "<dict>",
      "  <key>Label</key><string>" + o.label + "</string>",
      "  <key>ProgramArguments</key>",
      "  <array>",
      "    <string>" + o.wrapperPathUnix + "</string>",
      "  </array>",
      "  <key>StartCalendarInterval</key>" + interval,
      "  <key>StandardErrorPath</key><string>" + o.logPath + "</string>",
      "  <key>StandardOutPath</key><string>" + o.logPath + "</string>",
      "</dict>",
      "</plist>",
      "",
    ].join("\n");
  }

  // ── systemd (Linux) — service + timer, points at the wrapper ──
  function buildSystemdService(opts) {
    var o = withDefaults(opts);
    return [
      "[Unit]",
      "Description=Founders OS tick (detect + run --hold-only)",
      "",
      "[Service]",
      "Type=oneshot",
      "ExecStart=" + o.wrapperPathUnix,
      "",
    ].join("\n");
  }
  function buildSystemdTimer(opts) {
    var o = withDefaults(opts);
    return [
      "[Unit]",
      "Description=Schedule the Founders OS tick",
      "",
      "[Timer]",
      "OnCalendar=" + systemdOnCalendar(o),
      "Persistent=true",
      "",
      "[Install]",
      "WantedBy=timers.target",
      "",
    ].join("\n");
  }

  // ── cron (Linux/macOS) — one line at the wrapper ─────────
  function buildCronLine(opts) {
    var o = withDefaults(opts);
    return cronExpr(o) + " " + o.wrapperPathUnix + " >> " + o.logPath + " 2>&1\n";
  }

  // ── Task Scheduler (Windows) — registers the .cmd wrapper ──
  function buildTaskSchedulerCmd(opts) {
    var o = withDefaults(opts);
    var sched = o.cadence === "daily"
      ? "/SC DAILY /ST " + pad2(o.dailyHour) + ":00"
      : "/SC HOURLY";
    return [
      "REM Register the Founders OS tick with Windows Task Scheduler.",
      "REM Runs the wrapper .cmd, which sets creds and runs detect then run --hold-only.",
      'schtasks /Create /TN "' + o.taskName + '" /TR "' + o.wrapperPathWin + '" ' + sched + " /F",
      'schtasks /Query  /TN "' + o.taskName + '"',
      'schtasks /Run    /TN "' + o.taskName + '"',
      "",
    ].join("\n");
  }

  // ── Tick wrapper bodies (for the wizard's direct-download buttons) ──
  // Verbatim copies of integrations/scheduler/foundersos-tick.{sh,cmd}. The
  // wizard offers these as a download so the user does not have to fetch them
  // from GitHub by hand. integrations/scheduler/*.{sh,cmd} stay the canonical
  // source; setup-generators.test.mjs reads those files and asserts these
  // copies match byte-for-byte, so the embedded mirror can never drift. The
  // literals are injected from the real files by tools/sync-wrapper-bodies.mjs
  // (placeholders below get replaced) - do not hand-edit the strings.
  var WRAPPER_SH = "#!/usr/bin/env bash\n# ============================================================\n# Founders OS — tick wrapper (detect + run --hold-only)\n# ============================================================\n# One scheduled run = the check then the drain:\n#   1. founders-os-tick detect          fills the trigger_fires inbox\n#   2. founders-os-tick run --hold-only  stages every fire for human review\n# They run serially (detect finishes before run starts). Nothing is ever\n# performed — staged items wait in the approval queue for a human.\n#\n# Point your OS scheduler (launchd / systemd / cron) at THIS script instead\n# of the bare commands, so one job does both halves. See\n# founders-os-docs/guides/tick-cli-usage.md.\n#\n# Config (all optional, override via env or the env file):\n#   FOUNDERSOS_TICK_ENV   path to an env file with SUPABASE_URL /\n#                         SUPABASE_SECRET_KEY / FOUNDERS_OS_* (default\n#                         ~/.config/founders-os/foundersos-tick.env)\n#   FOUNDERSOS_TICK_BIN   how to invoke the tick CLI. Default\n#                         \"founders-os-tick\" assumes a GLOBAL install\n#                         (npm i -g @ourthinktank/founders-os). If you run\n#                         the package via npx instead, set this to the npx\n#                         form (the tick is the package's second bin):\n#                           npx -y -p @ourthinktank/founders-os@latest founders-os-tick\n#                         or, for local dev:\n#                           npx tsx /path/to/packages/mcp-server/src/tick.ts\n#                         It may be a multi-word command (paths must not\n#                         contain spaces).\n#   FOUNDERSOS_TICK_LOG   log file (default ~/.local/state/foundersos-tick.log)\n# ============================================================\n\nset -uo pipefail\n\nENV_FILE=\"${FOUNDERSOS_TICK_ENV:-$HOME/.config/founders-os/foundersos-tick.env}\"\nLOG_FILE=\"${FOUNDERSOS_TICK_LOG:-$HOME/.local/state/foundersos-tick.log}\"\n\nmkdir -p \"$(dirname \"$LOG_FILE\")\" 2>/dev/null || true\n\n# Load creds from the env file if present (scheduled jobs get a minimal\n# environment and do NOT inherit your shell profile). This is also where\n# FOUNDERSOS_TICK_BIN can be set, so resolve the command AFTER sourcing it.\nif [ -f \"$ENV_FILE\" ]; then\n  set -a\n  # shellcheck disable=SC1090\n  . \"$ENV_FILE\"\n  set +a\nfi\n\n# Scheduled jobs (launchd/systemd) start with a minimal PATH that usually\n# lacks node/npx, so an npx-based command would fail with \"command not found\".\n# Add the common install locations. nvm or other non-standard installs: set\n# PATH in the env file, or point FOUNDERSOS_TICK_BIN at an absolute npx path.\nexport PATH=\"/opt/homebrew/bin:/usr/local/bin:$HOME/.local/bin:$HOME/.npm-global/bin:$PATH\"\n\n# FOUNDERSOS_TICK_BIN may be a multi-word command (a global binary, an npx\n# invocation, or a dev `npx tsx ...` command). Split it into argv. Paths\n# with spaces are not supported - use a global install or a symlink.\nread -r -a TICK_CMD <<< \"${FOUNDERSOS_TICK_BIN:-founders-os-tick}\"\n\nlog() { printf '%s %s\\n' \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\" \"$*\" | tee -a \"$LOG_FILE\" >&2; }\n\nlog \"[tick-wrapper] start\"\n\n# 1. Detect — fill the inbox.\n\"${TICK_CMD[@]}\" detect --json | tee -a \"$LOG_FILE\"\nrc_detect=${PIPESTATUS[0]}\n\n# 2. Drain — stage whatever is pending. Runs even if detect failed, since the\n#    runner stages any inbox items that are already waiting.\n\"${TICK_CMD[@]}\" run --hold-only --json | tee -a \"$LOG_FILE\"\nrc_run=${PIPESTATUS[0]}\n\nlog \"[tick-wrapper] done (detect=$rc_detect run=$rc_run)\"\n\n# Exit non-zero if either step failed so the scheduler can alert.\n[ \"$rc_detect\" -eq 0 ] && [ \"$rc_run\" -eq 0 ]\n";
  var WRAPPER_CMD = "@echo off\nREM ============================================================\nREM Founders OS - tick wrapper (detect + run --hold-only)\nREM ============================================================\nREM One scheduled run = the check then the drain:\nREM   1. founders-os-tick detect           fills the trigger_fires inbox\nREM   2. founders-os-tick run --hold-only   stages every fire for human review\nREM They run serially. Nothing is performed - staged items wait for a human.\nREM Point Task Scheduler at THIS .cmd so one task does both halves.\nREM\nREM Credentials load from the env file (default\nREM %USERPROFILE%\\.config\\founders-os\\foundersos-tick.env), same as the .sh\nREM wrapper; override the path with FOUNDERSOS_TICK_ENV. FOUNDERSOS_TICK_BIN\nREM sets how the CLI is invoked (default \"founders-os-tick\"; use an npx form\nREM if you did not install globally).\nREM ============================================================\n\nset \"ENV_FILE=%FOUNDERSOS_TICK_ENV%\"\nif \"%ENV_FILE%\"==\"\" set \"ENV_FILE=%USERPROFILE%\\.config\\founders-os\\foundersos-tick.env\"\nif exist \"%ENV_FILE%\" (\n  for /f \"usebackq eol=# tokens=1,* delims==\" %%a in (\"%ENV_FILE%\") do set \"%%a=%%~b\"\n)\n\nif \"%FOUNDERSOS_TICK_BIN%\"==\"\" (set \"TICK=founders-os-tick\") else (set \"TICK=%FOUNDERSOS_TICK_BIN%\")\n\nset \"LOG_DIR=%USERPROFILE%\\.local\\state\"\nif not exist \"%LOG_DIR%\" mkdir \"%LOG_DIR%\" 2>nul\nset \"LOG=%LOG_DIR%\\foundersos-tick.log\"\n\necho %date% %time% [tick-wrapper] start>> \"%LOG%\"\n\ncall %TICK% detect --json>> \"%LOG%\" 2>&1\nset \"RC_DETECT=%ERRORLEVEL%\"\n\ncall %TICK% run --hold-only --json>> \"%LOG%\" 2>&1\nset \"RC_RUN=%ERRORLEVEL%\"\n\necho %date% %time% [tick-wrapper] done detect=%RC_DETECT% run=%RC_RUN%>> \"%LOG%\"\n\nif not \"%RC_DETECT%\"==\"0\" exit /b 1\nif not \"%RC_RUN%\"==\"0\" exit /b 1\nexit /b 0\n";

  function tickWrapperSh() { return WRAPPER_SH; }
  function tickWrapperCmd() { return WRAPPER_CMD; }

  // How the scheduled wrapper invokes the tick CLI. Most wizard users run
  // the package via npx (no global install), and the tick is the package's
  // SECOND bin, so npx needs `-p <pkg> founders-os-tick` (a bare
  // `npx @ourthinktank/founders-os` would run the MCP server, not the tick).
  // opts.tickBin overrides outright (a global "founders-os-tick", or a dev
  // "npx tsx /path/to/packages/mcp-server/src/tick.ts").
  function tickCommand(opts) {
    if (opts && opts.tickBin) return opts.tickBin;
    var spec = "@ourthinktank/founders-os" + (opts && opts.useLatest ? "@latest" : "");
    return "npx -y -p " + spec + " founders-os-tick";
  }

  // ── Bundle: everything the page needs for the scheduler section ──
  function buildSchedulerBundle(env, opts) {
    // The env file carries the tick command too, so the wrapper knows how to
    // run the package (npx vs global vs dev) without a separate config step.
    var envForFile = {};
    for (var k in env) envForFile[k] = env[k];
    envForFile.FOUNDERSOS_TICK_BIN = tickCommand(opts);
    return {
      envFile: buildEnvFile(envForFile),
      launchd: buildLaunchdPlist(opts),
      systemdService: buildSystemdService(opts),
      systemdTimer: buildSystemdTimer(opts),
      cron: buildCronLine(opts),
      taskScheduler: buildTaskSchedulerCmd(opts),
      wrapperSh: WRAPPER_SH,
      wrapperCmd: WRAPPER_CMD,
    };
  }

  var FoundersOSSetup = {
    DEFAULTS: DEFAULTS,
    sqlForDimension: sqlForDimension,
    buildMcpJson: buildMcpJson,
    buildEnvFile: buildEnvFile,
    tickCommand: tickCommand,
    buildLaunchdPlist: buildLaunchdPlist,
    buildSystemdService: buildSystemdService,
    buildSystemdTimer: buildSystemdTimer,
    buildCronLine: buildCronLine,
    buildTaskSchedulerCmd: buildTaskSchedulerCmd,
    tickWrapperSh: tickWrapperSh,
    tickWrapperCmd: tickWrapperCmd,
    buildSchedulerBundle: buildSchedulerBundle,
  };

  if (typeof module !== "undefined" && module.exports) module.exports = FoundersOSSetup;
  else root.FoundersOSSetup = FoundersOSSetup;
})(typeof self !== "undefined" ? self : this);
